// 原物品：N 种 N 个
//		=> 
// 新物品: N * logN 种 1 个
var h = MT::map_to_vector(yuan); // 原物品 { 物品重量 w：物品个数 }
var ve = vector<int>();          // 二进制拆分后新物品 { 物品新重量 nw：个数为 1 } 
fa(i, 0, vs(h)) {
	var[x, y] = h[i];
	for (int j = 1; j <= y; j <<= 1) { // 枚举物品个数
		y -= j;
		ve.pb(j * x);
	}
	if (y)ve.pb(y * x); // 存在余数
}

// 01 背包
var dp = vector<bool>(n + 1);
dp[0] = 1;
for (const var& x : ve)
	fb(i, n, x)
		dp[i] = dp[i] || dp[i - x];
